26	function DawShellInner(): React.JSX.Element {
27	  const registry = useMemo(() => new CommandRegistry(), []);
28	  const shortcuts = useMemo(() => new ShortcutMap(), []);
29	  const pool = useMediaPool();
30	  const undoManager = sharedUndoManager;
31	  const { saveNow, recoveryWarnings } = useSessionPersistence(defaultStorage);
32	  const [dismissed, setDismissed] = useState(false);
33	  const showRecovery = !dismissed && recoveryWarnings.length > 0;
34	
35	  const stableSaveNow = useCallback(() => saveNow(), [saveNow]);
36	
37	  useTransportShortcuts(registry, shortcuts);
38	  useSessionShortcuts(registry, shortcuts, undoManager, stableSaveNow);
39	  useKeyboardShortcuts(registry, shortcuts);
40	
41	  return (
42	    <div
43	      data-testid="daw-shell"
44	      style={{
