85	const DB_NAME = "brutalwav-sessions";
86	const DB_VERSION = 1;
87	const STORE_ACTIVE = "active";
88	const STORE_SAVED = "saved";
89	
90	function openSessionDb(): Promise<IDBDatabase> {
91	  return new Promise((resolve, reject) => {
92	    const req = indexedDB.open(DB_NAME, DB_VERSION);
93	    req.onupgradeneeded = (): void => {
94	      const db = req.result;
95	      if (!db.objectStoreNames.contains(STORE_ACTIVE)) {
96	        db.createObjectStore(STORE_ACTIVE);
97	      }
98	      if (!db.objectStoreNames.contains(STORE_SAVED)) {
99	        db.createObjectStore(STORE_SAVED);
100	      }
101	    };
102	    req.onsuccess = (): void => {
103	      resolve(req.result);
104	    };
105	    req.onerror = (): void => {
106	      reject(req.error ?? new Error("IndexedDB open failed"));
107	    };
108	  });
109	}
110	
111	function idbPut(
112	  db: IDBDatabase,
113	  store: string,
114	  key: string,
115	  value: unknown,
116	): Promise<void> {
117	  return new Promise((resolve, reject) => {
118	    const tx = db.transaction(store, "readwrite");
119	    tx.objectStore(store).put(value, key);
120	    tx.oncomplete = (): void => {
121	      resolve();
122	    };
123	    tx.onerror = (): void => {
124	      reject(tx.error ?? new Error("IDB put failed"));
125	    };
126	  });
127	}
128	
129	function idbGet<T>(
130	  db: IDBDatabase,
131	  store: string,
132	  key: string,
133	): Promise<T | undefined> {
134	  return new Promise((resolve, reject) => {
135	    const tx = db.transaction(store, "readonly");
136	    const req = tx.objectStore(store).get(key);
137	    req.onsuccess = (): void => {
138	      resolve(req.result as T | undefined);
139	    };
140	    req.onerror = (): void => {
141	      reject(req.error ?? new Error("IDB get failed"));
142	    };
143	  });
144	}
145	
146	function idbDelete(db: IDBDatabase, store: string, key: string): Promise<void> {
147	  return new Promise((resolve, reject) => {
148	    const tx = db.transaction(store, "readwrite");
149	    tx.objectStore(store).delete(key);
150	    tx.oncomplete = (): void => {
151	      resolve();
152	    };
153	    tx.onerror = (): void => {
154	      reject(tx.error ?? new Error("IDB delete failed"));
155	    };
156	  });
157	}
158	
159	function idbGetAll(
160	  db: IDBDatabase,
161	  store: string,
162	): Promise<{ keys: IDBValidKey[]; values: unknown[] }> {
163	  return new Promise((resolve, reject) => {
164	    const tx = db.transaction(store, "readonly");
165	    const objectStore = tx.objectStore(store);
166	    const keysReq = objectStore.getAllKeys();
167	    const valuesReq = objectStore.getAll();
168	    tx.oncomplete = (): void => {
169	      resolve({
170	        keys: keysReq.result,
171	        values: valuesReq.result as unknown[],
172	      });
173	    };
174	    tx.onerror = (): void => {
175	      reject(tx.error ?? new Error("IDB getAll failed"));
176	    };
177	  });
178	}
179	
180	export function createIndexedDBSessionStorage(): SessionStorage {
181	  let dbPromise: Promise<IDBDatabase> | null = null;
182	
183	  function getDb(): Promise<IDBDatabase> {
184	    if (dbPromise === null) {
185	      dbPromise = openSessionDb().catch((err: unknown) => {
186	        dbPromise = null;
187	        throw err;
188	      });
189	    }
190	    return dbPromise;
191	  }
192	
193	  return {
194	    async getDraft(): Promise<string | undefined> {
195	      const db = await getDb();
196	      return idbGet<string>(db, STORE_ACTIVE, "draft");
197	    },
198	    async putDraft(json): Promise<void> {
199	      const db = await getDb();
200	      await idbPut(db, STORE_ACTIVE, "draft", json);
201	    },
202	    async deleteDraft(): Promise<void> {
203	      const db = await getDb();
204	      await idbDelete(db, STORE_ACTIVE, "draft");
205	    },
206	    async getCurrent(): Promise<string | undefined> {
207	      const db = await getDb();
208	      return idbGet<string>(db, STORE_ACTIVE, "current");
209	    },
210	    async putCurrent(json): Promise<void> {
211	      const db = await getDb();
212	      await idbPut(db, STORE_ACTIVE, "current", json);
213	    },
214	    async getBackup(): Promise<string | undefined> {
215	      const db = await getDb();
216	      return idbGet<string>(db, STORE_ACTIVE, "backup");
217	    },
218	    async putBackup(json): Promise<void> {
219	      const db = await getDb();
220	      await idbPut(db, STORE_ACTIVE, "backup", json);
221	    },
222	    async listSessions(): Promise<SessionListEntry[]> {
223	      const db = await getDb();
224	      const { keys, values } = await idbGetAll(db, STORE_SAVED);
225	      const entries: SessionListEntry[] = [];
226	      for (let i = 0; i < keys.length; i++) {
227	        const entry = values[i] as
228	          | { name: string; json: string; updatedAt: number }
229	          | undefined;
230	        if (entry !== undefined) {
231	          entries.push({
232	            id: keys[i] as string,
233	            name: entry.name,
234	            updatedAt: entry.updatedAt,
235	          });
236	        }
237	      }
238	      return entries;
239	    },
240	    async getSession(id): Promise<string | undefined> {
241	      const db = await getDb();
242	      const entry = await idbGet<{
243	        name: string;
244	        json: string;
245	        updatedAt: number;
246	      }>(db, STORE_SAVED, id);
247	      return entry?.json;
248	    },
249	    async putSession(id, name, json): Promise<void> {
250	      const db = await getDb();
251	      await idbPut(db, STORE_SAVED, id, { name, json, updatedAt: Date.now() });
252	    },
253	    async deleteSession(id): Promise<void> {
254	      const db = await getDb();
255	      await idbDelete(db, STORE_SAVED, id);
256	    },
257	    async renameSession(id, name): Promise<void> {
258	      const db = await getDb();
259	      const entry = await idbGet<{
260	        name: string;
261	        json: string;
262	        updatedAt: number;
263	      }>(db, STORE_SAVED, id);
264	      if (entry !== undefined) {
265	        entry.name = name;
266	        await idbPut(db, STORE_SAVED, id, entry);
267	      }
268	    },
269	  };
270	}
