123	  tracks: [],
124	  clips: {},
125	  selectedTrackIds: [],
126	  selectedClipIds: [],
127	  selectedNoteIds: [],
128	
129	  // Transport actions
130	  play: () => {
131	    set({ transportState: "playing" });
132	  },
133	  pause: () => {
134	    set({ transportState: "paused" });
135	  },
136	  stop: () => {
137	    set({ transportState: "stopped", cursorSeconds: 0 });
138	  },
139	  setBpm: (bpm: number) => {
140	    const clamped = Math.min(999, Math.max(20, bpm));
