2	  sessionSchema,
3	  metaSectionSchema,
4	  transportSectionSchema,
5	  mixerSectionSchema,
6	  createDefaultSession,
7	  SESSION_VERSION,
8	  type SessionSchema,
9	} from "./session-schema";
10	import { z } from "zod/v4";
11	import { trackSchema, clipSchema } from "@state/track/index";
12	
13	export type RecoveryResult = {
14	  session: SessionSchema;
15	  warnings: string[];
16	};
17	
18	export function recoverSession(raw: string): RecoveryResult {
19	  const warnings: string[] = [];
20	  const defaults = createDefaultSession();
21	
22	  let parsed: unknown;
23	  try {
24	    parsed = JSON.parse(raw);
25	  } catch {
26	    return {
27	      session: defaults,
28	      warnings: ["Malformed JSON - using default session"],
29	    };
30	  }
31	
32	  // Try full schema parse first
33	  const fullResult = sessionSchema.safeParse(parsed);
34	  if (fullResult.success) {
35	    return { session: fullResult.data, warnings: [] };
36	  }
37	
38	  // Guard against non-object JSON values (null, number, string, array)
39	  if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
40	    return {
41	      session: defaults,
42	      warnings: ["Session data is not an object - using default session"],
43	    };
44	  }
45	
46	  // Partial recovery: parse each section independently
47	  const obj = parsed as Record<string, unknown>;
48	
49	  const metaResult = metaSectionSchema.safeParse(obj["meta"]);
50	  const meta = metaResult.success ? metaResult.data : defaults.meta;
51	  if (!metaResult.success) {
52	    warnings.push("Invalid meta section - using defaults");
53	  }
54	
55	  const transportResult = transportSectionSchema.safeParse(obj["transport"]);
56	  const transport = transportResult.success
57	    ? transportResult.data
58	    : defaults.transport;
59	  if (!transportResult.success) {
60	    warnings.push("Invalid transport section - using defaults");
61	  }
62	
63	  const tracksResult = z.array(trackSchema).safeParse(obj["tracks"]);
64	  const tracks = tracksResult.success ? tracksResult.data : defaults.tracks;
65	  if (!tracksResult.success) {
66	    warnings.push("Invalid tracks section - using defaults");
67	  }
68	
69	  const clipsResult = z.array(clipSchema).safeParse(obj["clips"]);
70	  const clips = clipsResult.success ? clipsResult.data : defaults.clips;
71	  if (!clipsResult.success) {
72	    warnings.push("Invalid clips section - using defaults");
73	  }
74	
75	  const mixerResult = mixerSectionSchema.safeParse(obj["mixer"]);
76	  const mixer = mixerResult.success ? mixerResult.data : defaults.mixer;
77	  if (!mixerResult.success) {
78	    warnings.push("Invalid mixer section - using defaults");
79	  }
80	
81	  const version =
82	    typeof obj["version"] === "number" ? obj["version"] : SESSION_VERSION;
83	  if (typeof obj["version"] !== "number") {
84	    warnings.push("Missing or invalid version - using current version");
85	  }
86	
87	  return {
88	    session: { version, meta, transport, tracks, clips, mixer },
89	    warnings,
90	  };
91	}
