7	} from "@state/synth/modulation-store";
8	import { useArpeggiatorStore, type ArpeggiatorStore } from "@state/arpeggiator";
9	import { useAutomationStore, type AutomationStore } from "@state/automation";
10	import type { SessionStorage } from "./session-storage";
11	import { createSaveQueue } from "./save-queue";
12	import { createAutoSave } from "./auto-save";
13	import { recoverSession } from "./session-recovery";
14	import { SESSION_VERSION } from "./session-schema";
15	import type { SessionSchema } from "./session-schema";
16	import {
17	  MAX_MOD_ROUTES,
18	  _seedRouteCounter,
19	} from "@audio/synth/modulation-types";
20	import { _seedLaneCounter } from "@audio/automation/automation-types";
