22	// Stored meta from the loaded session, preserved across auto-saves
23	let sessionMeta: { name: string; createdAt: number } = {
24	  name: "Untitled",
25	  createdAt: Date.now(),
26	};
27	
28	function serializeModulation():
29	  | Record<
30	      string,
31	      {
32	        id: string;
33	        source: string;
34	        destination: string;
35	        amount: number;
36	        bipolar: boolean;
37	      }[]
38	    >
39	  | undefined {
40	  const { matrices } = useModulationStore.getState();
41	  const entries = Object.entries(matrices);
42	  if (entries.length === 0) return undefined;
43	  const result: Record<
44	    string,
45	    {
46	      id: string;
47	      source: string;
48	      destination: string;
49	      amount: number;
50	      bipolar: boolean;
51	    }[]
52	  > = {};
53	  for (const [trackId, matrix] of entries) {
54	    result[trackId] = matrix.routes.map((r) => ({
55	      id: r.id,
56	      source: r.source,
57	      destination: r.destination,
58	      amount: r.amount,
59	      bipolar: r.bipolar,
60	    }));
61	  }
62	  return result;
63	}
