65	function storeToSession(): SessionSchema {
66	  const state = useDawStore.getState();
67	  const effectsState = useEffectsStore.getState();
68	
69	  // Convert effects store to session schema format
70	  const effects = Object.entries(effectsState.trackEffects).map(
71	    ([trackId, slots]) => ({
72	      trackId,
73	      slots: slots.map((s) => ({
74	        id: s.id,
75	        typeId: s.typeId,
76	        bypassed: s.bypassed,
77	        params: { ...s.params },
78	      })),
79	    }),
80	  );
81	
82	  // Convert arpeggiator store to session schema format
83	  const arpEntries = Object.entries(useArpeggiatorStore.getState().arps);
84	  const arpeggiator =
85	    arpEntries.length > 0
86	      ? arpEntries.map(([trackId, state]) => ({
87	          trackId,
88	          params: { ...state.params },
89	        }))
90	      : undefined;
91	
92	  // Convert automation store to session schema format
93	  const automationEntries = Object.entries(useAutomationStore.getState().lanes);
94	  const automation =
95	    automationEntries.length > 0
96	      ? automationEntries.map(([trackId, lanes]) => ({
97	          trackId,
98	          lanes: lanes.map((l) => ({
99	            id: l.id,
100	            trackId: l.trackId,
101	            target: l.target,
102	            points: l.points.map((p) => ({ ...p })),
103	            mode: l.mode,
104	            armed: l.armed,
105	          })),
106	        }))
107	      : undefined;
108	
109	  return {
110	    version: SESSION_VERSION,
111	    meta: {
112	      name: sessionMeta.name,
113	      createdAt: sessionMeta.createdAt,
114	      updatedAt: Date.now(),
115	    },
116	    transport: {
117	      bpm: state.bpm,
118	      loopEnabled: state.loopEnabled,
119	      loopStart: state.loopStart,
120	      loopEnd: state.loopEnd,
121	    },
122	    tracks: state.tracks.map((t) => ({ ...t })),
123	    clips: Object.values(state.clips),
124	    mixer: { masterVolume: state.masterVolume },
125	    effects: effects.length > 0 ? effects : undefined,
126	    modulation: serializeModulation(),
127	    arpeggiator,
128	    automation,
129	  };
130	}
131	
132	export function hydrateStore(session: SessionSchema): void {
133	  sessionMeta = {
134	    name: session.meta.name,
135	    createdAt: session.meta.createdAt,
136	  };
137	  const clips: Record<string, (typeof session.clips)[number]> = {};
138	  for (const clip of session.clips) {
139	    clips[clip.id] = clip;
140	  }
141	
142	  useDawStore.setState({
143	    bpm: session.transport.bpm,
144	    loopEnabled: session.transport.loopEnabled,
145	    loopStart: session.transport.loopStart,
146	    loopEnd: session.transport.loopEnd,
147	    tracks: session.tracks,
148	    clips,
149	    masterVolume: session.mixer.masterVolume,
150	  });
151	
152	  // Restore effects state (always clear first to avoid stale ghost inserts)
153	  const trackEffects: Record<
154	    string,
155	    readonly {
156	      id: string;
157	      typeId: string;
158	      bypassed: boolean;
159	      params: Record<string, number>;
160	    }[]
161	  > = {};
162	  if (session.effects) {
163	    for (const entry of session.effects) {
164	      trackEffects[entry.trackId] = entry.slots;
165	    }
166	  }
167	  useEffectsStore.setState({ trackEffects });
168	
169	  // Restore modulation state (Zod already validated source/destination as enums)
170	  const matrices: ModulationStore["matrices"] = {};
171	  let maxRouteNum = 0;
172	  if (session.modulation) {
173	    for (const [trackId, routes] of Object.entries(session.modulation)) {
174	      // Enforce MAX_MOD_ROUTES on load (addRoute guard is bypassed by setState)
175	      const clamped = routes.slice(0, MAX_MOD_ROUTES);
176	      matrices[trackId] = { routes: clamped };
177	      // Track highest route counter to avoid ID collisions
178	      for (const r of clamped) {
179	        const match = /^mod-(\d+)$/.exec(r.id);
180	        if (match) {
181	          maxRouteNum = Math.max(maxRouteNum, Number(match[1]));
182	        }
183	      }
184	    }
185	  }
186	  if (maxRouteNum > 0) {
187	    _seedRouteCounter(maxRouteNum);
188	  }
189	  useModulationStore.setState({ matrices });
190	
191	  // Restore arpeggiator state
192	  const arps: ArpeggiatorStore["arps"] = {};
193	  if (session.arpeggiator) {
194	    for (const entry of session.arpeggiator) {
195	      arps[entry.trackId] = { trackId: entry.trackId, params: entry.params };
196	    }
197	  }
198	  useArpeggiatorStore.setState({ arps });
199	
200	  // Restore automation state
201	  const automationLanes: AutomationStore["lanes"] = {};
202	  let maxLaneNum = 0;
203	  if (session.automation) {
204	    for (const entry of session.automation) {
205	      automationLanes[entry.trackId] = entry.lanes;
206	      for (const lane of entry.lanes) {
207	        const match = /^lane-(\d+)$/.exec(lane.id);
208	        if (match) {
209	          maxLaneNum = Math.max(maxLaneNum, Number(match[1]));
210	        }
211	      }
212	    }
213	  }
214	  if (maxLaneNum > 0) {
215	    _seedLaneCounter(maxLaneNum);
216	  }
217	  useAutomationStore.setState({ lanes: automationLanes });
218	}
219	
220	type SessionPersistenceResult = {
221	  saving: boolean;
222	  dirty: boolean;
223	  saveNow: () => Promise<void>;
224	  recoveryWarnings: string[];
225	};
226	
227	export function useSessionPersistence(
228	  storage: SessionStorage,
229	): SessionPersistenceResult {
230	  const [recoveryWarnings, setRecoveryWarnings] = useState<string[]>([]);
231	  const [saving, setSaving] = useState(false);
232	  const loadedRef = useRef(false);
233	
234	  const saveQueue = useMemo(() => createSaveQueue(storage), [storage]);
235	
236	  const autoSave = useMemo(
237	    () => createAutoSave(() => JSON.stringify(storeToSession()), saveQueue),
238	    [saveQueue],
239	  );
240	
241	  // Load session from storage on mount (draft-first for crash safety)
242	  useEffect(() => {
243	    if (loadedRef.current) return;
244	    loadedRef.current = true;
245	
246	    void (async (): Promise<void> => {
247	      // Check draft first — a crash between putDraft and putCurrent
248	      // means the draft is the most recent write attempt
249	      const draft = await storage.getDraft();
250	      const raw = draft ?? (await storage.getCurrent());
251	      if (raw !== undefined) {
252	        const result = recoverSession(raw);
253	        hydrateStore(result.session);
254	        if (draft !== undefined) {
255	          result.warnings.push(
256	            "Recovered from unsaved draft (possible crash recovery)",
257	          );
258	        }
259	        if (result.warnings.length > 0) {
260	          setRecoveryWarnings(result.warnings);
261	        }
262	      }
263	    })();
264	  }, [storage]);
265	
266	  // Start auto-save and subscribe to store changes
267	  useEffect(() => {
268	    autoSave.start();
269	
270	    const unsubDaw = useDawStore.subscribe(() => {
271	      autoSave.notifyChange();
272	    });
273	    const unsubEffects = useEffectsStore.subscribe(() => {
274	      autoSave.notifyChange();
275	    });
276	    const unsubMod = useModulationStore.subscribe(() => {
277	      autoSave.notifyChange();
278	    });
279	    const unsubArp = useArpeggiatorStore.subscribe(() => {
280	      autoSave.notifyChange();
281	    });
282	    const unsubAutomation = useAutomationStore.subscribe(() => {
283	      autoSave.notifyChange();
284	    });
285	
286	    return () => {
287	      autoSave.stop();
288	      unsubDaw();
289	      unsubEffects();
290	      unsubMod();
291	      unsubArp();
292	      unsubAutomation();
293	    };
294	  }, [autoSave]);
295	
296	  const saveNow = useCallback(async (): Promise<void> => {
297	    setSaving(true);
298	    await autoSave.saveNow();
299	    await saveQueue.flush();
300	    setSaving(false);
301	  }, [autoSave, saveQueue]);
302	
303	  return {
304	    saving,
305	    dirty: autoSave.dirty,
306	    saveNow,
307	    recoveryWarnings,
308	  };
309	}
