1	import type { SaveQueue } from "./save-queue";
2	
3	const DEFAULT_INTERVAL_MS = 30_000;
4	const DEFAULT_DEBOUNCE_MS = 2_000;
5	
6	export type AutoSave = {
7	  start(): void;
8	  stop(): void;
9	  notifyChange(): void;
10	  saveNow(): Promise<void>;
11	  readonly dirty: boolean;
12	};
13	
14	export function createAutoSave(
15	  getSessionJson: () => string,
16	  saveQueue: SaveQueue,
17	  intervalMs: number = DEFAULT_INTERVAL_MS,
18	  debounceMs: number = DEFAULT_DEBOUNCE_MS,
19	): AutoSave {
20	  let isDirty = false;
21	  let debounceTimer: ReturnType<typeof setTimeout> | null = null;
22	  let intervalTimer: ReturnType<typeof setInterval> | null = null;
23	
24	  function save(): void {
25	    if (!isDirty) return;
26	    isDirty = false;
27	    void saveQueue.enqueue(getSessionJson());
28	  }
29	
30	  return {
31	    start(): void {
32	      intervalTimer = setInterval(() => {
33	        save();
34	      }, intervalMs);
35	    },
36	
37	    stop(): void {
38	      if (debounceTimer !== null) {
39	        clearTimeout(debounceTimer);
40	        debounceTimer = null;
41	      }
42	      if (intervalTimer !== null) {
43	        clearInterval(intervalTimer);
44	        intervalTimer = null;
45	      }
46	    },
47	
48	    notifyChange(): void {
49	      isDirty = true;
50	      if (debounceTimer !== null) {
51	        clearTimeout(debounceTimer);
52	      }
53	      debounceTimer = setTimeout(() => {
54	        debounceTimer = null;
55	        save();
56	      }, debounceMs);
57	    },
58	
59	    async saveNow(): Promise<void> {
60	      isDirty = false;
61	      if (debounceTimer !== null) {
62	        clearTimeout(debounceTimer);
63	        debounceTimer = null;
64	      }
65	      await saveQueue.enqueue(getSessionJson());
66	    },
67	
68	    get dirty(): boolean {
69	      return isDirty;
70	    },
71	  };
72	}
