13	  async function doSave(json: string): Promise<void> {
14	    const previous = await storage.getCurrent();
15	    await storage.putDraft(json);
16	    await storage.putCurrent(json);
17	    if (previous !== undefined) {
18	      await storage.putBackup(previous);
19	    }
20	    await storage.deleteDraft();
21	  }
22	
23	  async function processQueue(): Promise<void> {
24	    while (queued !== null) {
25	      const next = queued;
26	      queued = null;
27	      await doSave(next);
28	    }
29	  }
30	
31	  return {
32	    enqueue(sessionJson: string): Promise<void> {
33	      if (inflight !== null) {
34	        queued = sessionJson;
35	        return inflight;
36	      }
37	      inflight = (async () => {
38	        try {
39	          await doSave(sessionJson);
40	          await processQueue();
41	        } catch (err) {
42	          queued = null;
43	          throw err;
44	        } finally {
45	          inflight = null;
46	        }
47	      })();
48	      return inflight;
49	    },
50	
51	    async flush(): Promise<void> {
52	      if (inflight !== null) {
53	        await inflight;
54	      }
55	    },
56	
57	    get pending(): boolean {
58	      return inflight !== null;
59	    },
60	  };
61	}
